use actix_web::{web, App, HttpServer, HttpRequest, HttpResponse, middleware};
use actix_files::NamedFile;
use std::path::{Path, PathBuf};

async fn serve_file(req: HttpRequest) -> HttpResponse {
    let filename: String = req.match_info().query("filename").to_string();

    // Reject any filename that contains null bytes
    if filename.contains('\0') {
        return HttpResponse::BadRequest().body("Invalid filename");
    }

    // Reject absolute paths
    let requested_path = Path::new(&filename);
    if requested_path.is_absolute() {
        return HttpResponse::BadRequest().body("Absolute paths are not allowed");
    }

    // Reject any path components that are traversal segments
    for component in requested_path.components() {
        match component {
            std::path::Component::Normal(_) => {
                // This is fine
            }
            _ => {
                // Reject ParentDir (..), RootDir (/), CurDir (.), Prefix (Windows drive letters)
                return HttpResponse::BadRequest().body("Invalid path components detected");
            }
        }
    }

    // Define the base uploads directory and canonicalize it
    let base_dir = match std::fs::canonicalize("./uploads") {
        Ok(path) => path,
        Err(_) => {
            return HttpResponse::InternalServerError().body("Uploads directory not found");
        }
    };

    // Join the filename to the base directory
    let joined_path = base_dir.join(&filename);

    // Canonicalize the joined path to resolve any symlinks or remaining tricks
    let canonical_path = match std::fs::canonicalize(&joined_path) {
        Ok(path) => path,
        Err(_) => {
            return HttpResponse::NotFound().body("File not found");
        }
    };

    // Verify the canonical path is strictly within the base directory
    if !canonical_path.starts_with(&base_dir) {
        return HttpResponse::Forbidden().body("Access denied: path traversal detected");
    }

    // Verify it's a regular file (not a directory or other special file)
    if !canonical_path.is_file() {
        return HttpResponse::NotFound().body("Not a regular file");
    }

    // Determine content type based on file extension
    let content_type = guess_content_type(&canonical_path);

    // Serve the file
    match NamedFile::open(&canonical_path) {
        Ok(named_file) => {
            match std::fs::read(&canonical_path) {
                Ok(contents) => {
                    HttpResponse::Ok()
                        .content_type(content_type)
                        .body(contents)
                }
                Err(_) => HttpResponse::InternalServerError().body("Failed to read file"),
            }
        }
        Err(_) => HttpResponse::NotFound().body("File not found"),
    }
}

fn guess_content_type(path: &Path) -> &'static str {
    match path.extension().and_then(|ext| ext.to_str()) {
        Some("html") | Some("htm") => "text/html; charset=utf-8",
        Some("css") => "text/css; charset=utf-8",
        Some("js") => "application/javascript; charset=utf-8",
        Some("json") => "application/json; charset=utf-8",
        Some("xml") => "application/xml; charset=utf-8",
        Some("txt") => "text/plain; charset=utf-8",
        Some("csv") => "text/csv; charset=utf-8",
        Some("png") => "image/png",
        Some("jpg") | Some("jpeg") => "image/jpeg",
        Some("gif") => "image/gif",
        Some("svg") => "image/svg+xml",
        Some("webp") => "image/webp",
        Some("ico") => "image/x-icon",
        Some("bmp") => "image/bmp",
        Some("pdf") => "application/pdf",
        Some("zip") => "application/zip",
        Some("gz") | Some("gzip") => "application/gzip",
        Some("tar") => "application/x-tar",
        Some("mp3") => "audio/mpeg",
        Some("wav") => "audio/wav",
        Some("ogg") => "audio/ogg",
        Some("mp4") => "video/mp4",
        Some("webm") => "video/webm",
        Some("avi") => "video/x-msvideo",
        Some("woff") => "font/woff",
        Some("woff2") => "font/woff2",
        Some("ttf") => "font/ttf",
        Some("otf") => "font/otf",
        Some("wasm") => "application/wasm",
        _ => "application/octet-stream",
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    // Ensure the uploads directory exists
    std::fs::create_dir_all("./uploads")?;

    println!("Starting file server on http://127.0.0.1:8080");
    println!("Serving files from ./uploads directory");

    HttpServer::new(|| {
        App::new()
            .route("/files/{filename:.*}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}

